TIER_PROF_LIMIT = {"ddo": 6, "yovayshi": 8, "onett": 10}


def get_profile(top_type: str, test_id: str) -> dict:
    rich = PROF_RICH.get(top_type, {})
    limit = TIER_PROF_LIMIT.get(test_id, 6)
    return {
        "emoji": rich.get("emoji", "🎯"),
        "salary": rich.get("salary"),
        "description": rich.get("description", "Ведущий тип профессиональных интересов"),
        "profs": rich.get("profs", [])[:limit],
    }
